//! Markdown parsing for agent messages

use ratatui::style::{Color, Modifier, Style};
use ratatui::text::Span;
use crate::theme::C;

/// Parsed inline markdown span for styling.
#[derive(Debug, Clone, PartialEq)]
pub struct MdSpan {
    pub content: String,
    pub style: Style,
}

/// Parse inline markdown bold (**text**), italic (*text*), and code (`text`) into styled spans.
pub fn parse_inline_markdown(text: &str) -> Vec<MdSpan> {
    parse_inline_markdown_with_color(text, C.fg_bright)
}

/// Parse inline markdown with a custom base foreground color.
pub fn parse_inline_markdown_with_color(text: &str, base_color: Color) -> Vec<MdSpan> {
    let mut spans = Vec::new();
    let mut chars = text.chars().peekable();
    let mut current = String::new();
    let base = Style::default().fg(base_color);

    while let Some(c) = chars.next() {
        if c == '*' && chars.peek() == Some(&'*') {
            chars.next();
            flush_plain(&mut current, &mut spans, base);
            if let Some((found, inner)) = parse_delimited(&mut chars, "**") {
                if found {
                    spans.push(MdSpan { content: inner, style: base.add_modifier(Modifier::BOLD) });
                } else {
                    current.push_str("**");
                    current.push_str(&inner);
                }
            }
        } else if c == '`' {
            flush_plain(&mut current, &mut spans, base);
            let mut code_text = String::new();
            for cc in chars.by_ref() {
                if cc == '`' {
                    break;
                }
                code_text.push(cc);
            }
            spans.push(MdSpan {
                content: code_text,
                style: Style::default().fg(C.accent).bg(C.code_bg),
            });
        } else if c == '*' {
            flush_plain(&mut current, &mut spans, base);
            if let Some((found, inner)) = parse_delimited(&mut chars, "*") {
                if found {
                    spans.push(MdSpan { content: inner, style: base.add_modifier(Modifier::ITALIC) });
                } else {
                    current.push('*');
                    current.push_str(&inner);
                }
            }
        } else {
            current.push(c);
        }
    }
    flush_plain(&mut current, &mut spans, base);
    spans
}

fn parse_delimited(chars: &mut std::iter::Peekable<impl Iterator<Item = char>>, delim: &str) -> Option<(bool, String)> {
    let mut text = String::new();
    while let Some(c) = chars.next() {
        if delim == "*" && c == '*' {
            return Some((true, text));
        }
        if delim == "**" && c == '*' && chars.peek() == Some(&'*') {
            chars.next();
            return Some((true, text));
        }
        text.push(c);
    }
    Some((false, text))
}

fn flush_plain(current: &mut String, spans: &mut Vec<MdSpan>, style: Style) {
    if !current.is_empty() {
        spans.push(MdSpan {
            content: std::mem::take(current),
            style,
        });
    }
}

/// A block of text or code extracted from markdown.
#[derive(Debug, Clone, PartialEq)]
pub enum CodeBlock {
    Text(String),
    Code { lang: String, content: String },
    List { ordered: bool, items: Vec<String> },
    Blockquote(String),
}

/// Extract code blocks (``` fenced) from text.
/// Returns vec of Text/Code segments in order.
fn flush_text(lines: &mut Vec<&str>, blocks: &mut Vec<CodeBlock>) {
    if !lines.is_empty() {
        blocks.push(CodeBlock::Text(lines.join("\n")));
        lines.clear();
    }
}

pub fn extract_code_blocks(text: &str) -> Vec<CodeBlock> {
    let mut blocks = Vec::new();
    let mut in_code = false;
    let mut lang = String::new();
    let mut code_lines: Vec<&str> = Vec::new();
    let mut text_lines: Vec<&str> = Vec::new();
    let mut in_list = false;
    let mut list_ordered = false;
    let mut list_items: Vec<String> = Vec::new();
    let mut current_list_item = String::new();
    let mut in_blockquote = false;
    let mut blockquote_lines: Vec<&str> = Vec::new();

    fn flush_list(items: &mut Vec<String>, blocks: &mut Vec<CodeBlock>, ordered: bool) {
        if !items.is_empty() {
            blocks.push(CodeBlock::List { ordered, items: std::mem::take(items) });
        }
    }

    fn flush_blockquote(lines: &mut Vec<&str>, blocks: &mut Vec<CodeBlock>) {
        if !lines.is_empty() {
            blocks.push(CodeBlock::Blockquote(lines.join("\n")));
            lines.clear();
        }
    }

    for line in text.lines() {
        // Code blocks (``` fenced)
        if line.starts_with("```") {
            flush_text(&mut text_lines, &mut blocks);
            flush_list(&mut list_items, &mut blocks, list_ordered);
            flush_blockquote(&mut blockquote_lines, &mut blocks);
            if in_code {
                blocks.push(CodeBlock::Code {
                    lang: std::mem::take(&mut lang),
                    content: code_lines.join("\n"),
                });
                code_lines.clear();
            } else {
                // Safe because we checked starts_with("```") above
                let rest = line.strip_prefix("```").expect("already checked starts_with");
                lang = rest.trim().to_string();
            }
            in_code = !in_code;
            continue;
        }

        if in_code {
            code_lines.push(line);
            continue;
        }

        // Blockquotes (> )
        if let Some(stripped) = line.strip_prefix("> ") {
            flush_text(&mut text_lines, &mut blocks);
            flush_list(&mut list_items, &mut blocks, list_ordered);
            blockquote_lines.push(stripped);
            in_blockquote = true;
            continue;
        } else if in_blockquote && line.starts_with(">") {
            blockquote_lines.push(line.trim_start_matches('>').trim_start());
            continue;
        } else if in_blockquote {
            flush_blockquote(&mut blockquote_lines, &mut blocks);
            in_blockquote = false;
        }

        // Lists (- item, * item, 1. item, 2. item)
        let is_unordered = line.starts_with("- ") || line.starts_with("* ");
        let is_ordered = line.chars().next().map(|c| c.is_ascii_digit()).unwrap_or(false)
            && line.contains('.');

        if is_unordered || is_ordered {
            flush_text(&mut text_lines, &mut blocks);
            flush_blockquote(&mut blockquote_lines, &mut blocks);

            // Check if this continues a list
            let item_text = if is_unordered {
                line[2..].trim().to_string()
            } else {
                // "1. item" -> "item"
                line.split_once('.').map(|(_, rest)| rest.trim().to_string()).unwrap_or_default()
            };
            let this_ordered = is_ordered;

            if in_list && list_ordered == this_ordered {
                // Continue current list
                if !current_list_item.is_empty() {
                    list_items.push(std::mem::take(&mut current_list_item));
                }
                current_list_item = item_text;
            } else {
                // Start new list
                flush_list(&mut list_items, &mut blocks, list_ordered);
                list_ordered = this_ordered;
                current_list_item = item_text;
                in_list = true;
            }
            continue;
        } else if in_list {
            // Non-list line - check if it's a continuation of the current item
            let trimmed = line.trim_start();
            if !trimmed.is_empty() && !trimmed.starts_with("> ") {
                // Check if this looks like continuation (indented)
                let leading_spaces = line.len() - line.trim_start().len();
                if leading_spaces >= 2 {
                    current_list_item.push(' ');
                    current_list_item.push_str(trimmed);
                    continue;
                }
            }
            // End of list
            if !current_list_item.is_empty() {
                list_items.push(std::mem::take(&mut current_list_item));
            }
            flush_list(&mut list_items, &mut blocks, list_ordered);
            in_list = false;
        }

        text_lines.push(line);
    }

    // Flush remaining content
    if in_code {
        text_lines.push("```");
        text_lines.extend(code_lines);
    }
    if in_list {
        if !current_list_item.is_empty() {
            list_items.push(current_list_item);
        }
        flush_list(&mut list_items, &mut blocks, list_ordered);
    }
    if in_blockquote {
        flush_blockquote(&mut blockquote_lines, &mut blocks);
    }
    flush_text(&mut text_lines, &mut blocks);
    blocks
}

/// Convert MdSpan slices to ratatui Spans.
pub fn md_to_spans(md_spans: &[MdSpan]) -> Vec<Span<'static>> {
    md_spans
        .iter()
        .map(|s| Span::styled(s.content.clone(), s.style))
        .collect()
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn inline_code_parsed() {
        let spans = parse_inline_markdown("use `cargo test` to run");
        let code = spans.iter().find(|s| s.content == "cargo test");
        assert!(code.is_some(), "Should have code span 'cargo test'");
        assert_eq!(code.unwrap().style.fg, Some(C.accent));
        assert!(code.unwrap().style.bg.is_some(), "Code should have bg");
    }

    #[test]
    fn bold_text_parsed() {
        let spans = parse_inline_markdown("hello **world** test");
        let bold = spans.iter().find(|s| s.content == "world");
        assert!(bold.is_some());
        assert_eq!(bold.unwrap().style.add_modifier, Modifier::BOLD);
    }

    #[test]
    fn italic_text_parsed() {
        let spans = parse_inline_markdown("hello *world* test");
        let italic = spans.iter().find(|s| s.content == "world");
        assert!(italic.is_some());
        assert_eq!(italic.unwrap().style.add_modifier, Modifier::ITALIC);
    }

    #[test]
    fn detects_code_block() {
        let text = "Some text\n```rust\nfn main() {}\n```\nMore text";
        let blocks = extract_code_blocks(text);
        assert_eq!(blocks.len(), 3);
        assert!(matches!(&blocks[0], CodeBlock::Text(_)));
        assert!(matches!(&blocks[1], CodeBlock::Code { lang, .. } if lang == "rust"));
        assert!(matches!(&blocks[2], CodeBlock::Text(_)));
    }

    #[test]
    fn unclosed_code_block_becomes_text() {
        let text = "```rust\nfn main() {}";
        let blocks = extract_code_blocks(text);
        assert_eq!(blocks.len(), 1);
        assert!(matches!(&blocks[0], CodeBlock::Text(t) if t.contains("fn main"))
        );
    }
}

//! Diff rendering for edit tool output
//!
//! Parses unified diff format and renders with syntax highlighting:
//! - Added lines: green
//! - Removed lines: red
//! - Context lines: default color
//! - Line numbers: dim

use ratatui::style::{Color, Modifier, Style};
use ratatui::text::{Line, Span};

use crate::theme::C;

/// A parsed line from a unified diff
#[derive(Debug, Clone, PartialEq)]
pub enum DiffLineType {
    /// File header (--- or +++)
    FileHeader,
    /// Hunk header (@@ ... @@)
    HunkHeader,
    /// Added line (+)
    Added,
    /// Removed line (-)
    Removed,
    /// Context line (unchanged)
    Context,
}

/// A single line with its type and content
#[derive(Debug, Clone)]
pub struct ParsedDiffLine {
    pub line_type: DiffLineType,
    pub content: String,
    pub line_number: Option<u32>,
}

/// Parsed diff with metadata
#[derive(Debug, Clone)]
pub struct ParsedDiff {
    pub lines: Vec<ParsedDiffLine>,
    pub old_path: Option<String>,
    pub new_path: Option<String>,
}

/// Check if text looks like a unified diff
pub fn is_diff_output(text: &str) -> bool {
    let first_line = text.lines().next().unwrap_or("");
    first_line.starts_with("--- ") || first_line.starts_with("diff ")
}

/// Parse unified diff format
pub fn parse_diff(text: &str) -> ParsedDiff {
    let mut lines = Vec::new();
    let mut old_path = None;
    let mut new_path = None;
    let mut old_line_num: Option<u32> = None;
    let mut new_line_num: Option<u32> = None;

    for line in text.lines() {
        if line.starts_with("--- ") {
            old_path = Some(line.trim_start_matches("--- ").to_string());
            lines.push(ParsedDiffLine {
                line_type: DiffLineType::FileHeader,
                content: line.to_string(),
                line_number: None,
            });
        } else if line.starts_with("+++ ") {
            new_path = Some(line.trim_start_matches("+++ ").to_string());
            lines.push(ParsedDiffLine {
                line_type: DiffLineType::FileHeader,
                content: line.to_string(),
                line_number: None,
            });
        } else if line.starts_with("@@ ") {
            // Parse hunk header: @@ -start,count +start,count @@
            let parts: Vec<&str> = line.split_whitespace().collect();
            if parts.len() >= 2 {
                let ranges: Vec<&str> = parts[1].split(',').collect();
                if ranges[0].starts_with('-') {
                    old_line_num = ranges[0].trim_start_matches('-').parse().ok();
                }
                let new_parts: Vec<&str> = parts.get(2).unwrap_or(&"").split(',').collect();
                if new_parts[0].starts_with('+') {
                    new_line_num = Some(new_parts[0].trim_start_matches('+').parse().unwrap_or(1));
                }
            }
            lines.push(ParsedDiffLine {
                line_type: DiffLineType::HunkHeader,
                content: line.to_string(),
                line_number: None,
            });
        } else if line.starts_with('+') && !line.starts_with("+++") {
            let num = new_line_num.take();
            if let Some(ref mut n) = new_line_num {
                *n += 1;
            }
            lines.push(ParsedDiffLine {
                line_type: DiffLineType::Added,
                content: line[1..].to_string(),
                line_number: num,
            });
        } else if line.starts_with('-') && !line.starts_with("---") {
            let num = old_line_num.take();
            if let Some(ref mut n) = old_line_num {
                *n += 1;
            }
            lines.push(ParsedDiffLine {
                line_type: DiffLineType::Removed,
                content: line[1..].to_string(),
                line_number: num,
            });
        } else if line.starts_with(' ') {
            let num = match (&old_line_num, &new_line_num) {
                (Some(o), Some(_n)) => Some(*o),
                (Some(o), None) => Some(*o),
                (None, Some(n)) => Some(*n),
                (None, None) => None,
            };
            if let Some(ref mut o) = old_line_num {
                *o += 1;
            }
            if let Some(ref mut n) = new_line_num {
                *n += 1;
            }
            lines.push(ParsedDiffLine {
                line_type: DiffLineType::Context,
                content: line.strip_prefix(' ').unwrap_or(line).to_string(),
                line_number: num,
            });
        } else if line.is_empty() {
            // Empty line in diff content
            lines.push(ParsedDiffLine {
                line_type: DiffLineType::Context,
                content: String::new(),
                line_number: None,
            });
        }
        // Skip any other lines (like \ No newline at end of file)
    }

    ParsedDiff { lines, old_path, new_path }
}

/// Style for a diff line based on its type
pub fn diff_line_style(line_type: &DiffLineType) -> Style {
    match line_type {
        DiffLineType::Added => Style::default().fg(C.success),
        DiffLineType::Removed => Style::default().fg(Color::Red),
        DiffLineType::HunkHeader => Style::default().fg(C.accent).add_modifier(Modifier::BOLD),
        DiffLineType::FileHeader => Style::default().fg(C.dim),
        DiffLineType::Context => Style::default().fg(C.fg),
    }
}

/// Prefix character for a diff line
pub fn diff_line_prefix(line_type: &DiffLineType) -> &'static str {
    match line_type {
        DiffLineType::Added => "+",
        DiffLineType::Removed => "-",
        DiffLineType::Context => " ",
        DiffLineType::HunkHeader => "",
        DiffLineType::FileHeader => "",
    }
}

/// Render a parsed diff to styled ratatui lines
pub fn render_diff(diff: &ParsedDiff, gutter_width: usize) -> Vec<Line<'static>> {
    let mut output = Vec::new();

    for parsed in &diff.lines {
        let prefix = diff_line_prefix(&parsed.line_type);
        let style = diff_line_style(&parsed.line_type);

        let line_num_str = match parsed.line_number {
            Some(n) => format!("{:>width$}", n, width = gutter_width),
            None => " ".repeat(gutter_width),
        };

        let spans: Vec<Span<'static>> = vec![
            Span::styled(line_num_str, Style::default().fg(C.dim)),
            Span::styled(prefix, style),
            Span::styled(parsed.content.clone(), style),
        ];

        output.push(Line::from(spans));
    }

    output
}

/// Render diff text directly (convenience function)
pub fn render_diff_text(text: &str) -> Vec<Line<'static>> {
    if !is_diff_output(text) {
        // Not a diff, return as plain text
        return text.lines()
            .map(|l| Line::from(l.to_string()))
            .collect();
    }

    let diff = parse_diff(text);
    let gutter_width = 4;
    render_diff(&diff, gutter_width)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn detects_diff_output() {
        let diff = "--- a/file.txt\n+++ b/file.txt\n@@ -1,3 +1,4 @@\n line1\n-old\n+new\n line3";
        assert!(is_diff_output(diff));
    }

    #[test]
    fn rejects_non_diff_output() {
        let text = "Hello, this is regular text";
        assert!(!is_diff_output(text));
    }

    #[test]
    fn parses_simple_diff() {
        let diff = "--- a/test.txt\n+++ b/test.txt\n@@ -1,3 +1,4 @@\n line1\n-old\n+new\n line3";
        let parsed = parse_diff(diff);

        assert_eq!(parsed.old_path, Some("a/test.txt".to_string()));
        assert_eq!(parsed.new_path, Some("b/test.txt".to_string()));
        assert!(!parsed.lines.is_empty());

        // Find added line
        let added = parsed.lines.iter().find(|l| l.line_type == DiffLineType::Added);
        assert!(added.is_some());
        assert_eq!(added.unwrap().content, "new");

        // Find removed line
        let removed = parsed.lines.iter().find(|l| l.line_type == DiffLineType::Removed);
        assert!(removed.is_some());
        assert_eq!(removed.unwrap().content, "old");
    }

    #[test]
    fn parses_hunk_header() {
        let diff = "@@ -1,5 +1,7 @@ context";
        let parsed = parse_diff(diff);

        assert_eq!(parsed.lines.len(), 1);
        assert!(matches!(parsed.lines[0].line_type, DiffLineType::HunkHeader));
    }

    #[test]
    fn diff_line_styles() {
        assert_eq!(diff_line_style(&DiffLineType::Added).fg, Some(C.success));
        assert_eq!(diff_line_style(&DiffLineType::Removed).fg, Some(Color::Red));
        assert_eq!(diff_line_style(&DiffLineType::Context).fg, Some(C.fg));
    }

    #[test]
    fn diff_line_prefixes() {
        assert_eq!(diff_line_prefix(&DiffLineType::Added), "+");
        assert_eq!(diff_line_prefix(&DiffLineType::Removed), "-");
        assert_eq!(diff_line_prefix(&DiffLineType::Context), " ");
    }

    #[test]
    fn render_diff_output() {
        let diff = "--- a/test.txt\n+++ b/test.txt\n@@ -1 +1 @@\n-old\n+new";
        let lines = render_diff_text(diff);

        assert!(!lines.is_empty());
        // Each line should have spans
        for line in &lines {
            assert!(!line.spans.is_empty());
        }
    }

    #[test]
    fn render_non_diff_as_plain() {
        let text = "This is not a diff";
        let lines = render_diff_text(text);

        assert_eq!(lines.len(), 1);
        assert_eq!(lines[0].spans[0].content, "This is not a diff");
    }

    #[test]
    fn empty_content() {
        let diff = "";
        let lines = render_diff_text(diff);
        assert!(lines.is_empty());
    }

    #[test]
    fn preserves_line_numbers() {
        let diff = "@@ -10,3 +10,4 @@\n context\n-old\n+new\n+added";
        let parsed = parse_diff(diff);

        let removed = parsed.lines.iter().find(|l| l.line_type == DiffLineType::Removed);
        assert!(removed.is_some());
        assert_eq!(removed.unwrap().line_number, Some(11));
    }
}

